import { useState } from "react";
import MainHeaderTab from "./Tab";
import classes from "./TabBar.module.css";
import { useLocation } from "react-router-dom";

const TabBar = () => {
  let { pathname, state } = useLocation();
  const [selectedTab, setSelectedTab] = useState(pathname);

  if (state._isRedirect) {
    state = "/friends/all"
  }

  const tabState = {
    selectedTab: state,
    setSelectedTab: setSelectedTab,
  };

  return (
    <div className={classes["tab-bar"]}>
      <MainHeaderTab
        link="/friends/online"
        title="Online"
        tabState={tabState}
      ></MainHeaderTab>
      <MainHeaderTab
        link="/friends/all"
        title="All"
        tabState={tabState}
      ></MainHeaderTab>
      <MainHeaderTab
        link="/friends/pending"
        title="Pending"
        tabState={tabState}
      ></MainHeaderTab>
      <MainHeaderTab
        link="/friends/blocked"
        title="Blocked"
        tabState={tabState}
      ></MainHeaderTab>
      <MainHeaderTab
        link="/friends/add"
        title="Add Friend"
        tabState={tabState}
      ></MainHeaderTab>
    </div>
  );
};

export default TabBar;
